import{c as n}from"./app.8935f5f1.js";const e={},o=n('<h2 id="conf" tabindex="-1"><a class="header-anchor" href="#conf" aria-hidden="true">#</a> conf</h2><div class="language-conf ext-conf"><pre class="language-conf"><code>\n#user  nobody;\nworker_processes  1;\n\n#error_log  logs/error.log;\n#error_log  logs/error.log  notice;\n#error_log  logs/error.log  info;\n\n#pid        logs/nginx.pid;\n\n\nevents {\n    worker_connections  1024;\n}\n\n\nhttp {\n    include       mime.types;\n    default_type  application/octet-stream;\n\n    #log_format  main  &#39;$remote_addr - $remote_user [$time_local] &quot;$request&quot; &#39;\n    #                  &#39;$status $body_bytes_sent &quot;$http_referer&quot; &#39;\n    #                  &#39;&quot;$http_user_agent&quot; &quot;$http_x_forwarded_for&quot;&#39;;\n    server_tokens off;\n    #access_log  logs/access.log  main;\n\n    sendfile        on;\n    #tcp_nopush     on;\n\n    #keepalive_timeout  0;\n    keepalive_timeout  65;\n\n    #gzip  on;\n\n    server {\n        listen       80;\n        server_name  www.aabc.com;\n\n        #charset koi8-r;\n\n        #access_log  logs/host.access.log  main;\n\n\tlocation /cscs {\n\t\tproxy_pass http://127.0.0.1:8800;\n\t\tproxy_redirect off;\n\t\tproxy_set_header X-Real-IP $remote_addr;\n\t\tproxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\n\t\tproxy_set_header Host $host:$server_port;\n \t\tclient_max_body_size 10m; \n \t\tclient_body_buffer_size 128k; \n \t\tproxy_connect_timeout 90; \n \t\tproxy_send_timeout 90; \n \t\tproxy_read_timeout 90; \n \t\tproxy_buffer_size 4k; \n\t\tproxy_buffers 4 32k; \n\t\tproxy_busy_buffers_size 64k; \n\t\tproxy_temp_file_write_size 64k;\n\t}\n\t\n\t#  静动分离，就是将css、js、jpg等静态资源和jsp等动态资源分开处理，以此提高服务器响应速度，提高性能。\n\t# 在nginx的安装根目录下创建resources   ui\n\t\n\t# 把项目的resources/static里面的所有内容放到nginx/resources里面\n\t\n\tlocation ~* \\.(css|js|html|png|jpg|gif){\n\t\troot ui;     # 当匹配到 .css 这个规则时指向nginx目录里面的/html文件夹\n\t\t# 缓存天数  7天\n\t\texpires 7d;\n\t}\n  \n    }\n \n}\n</code></pre></div><h2 id="配置解释" tabindex="-1"><a class="header-anchor" href="#配置解释" aria-hidden="true">#</a> 配置解释</h2><div class="language-conf ext-conf"><pre class="language-conf"><code>\n    # 负载均衡\n    upstream www.cc.com{\n        server 27.10.158.252:7011 weight=1 max_fails=2 fail_timeout=30s;\n        server 27.10.158.247:8800 weight=2 max_fails=2 fail_timeout=30s;\n        # 多应用的 session 共享问题\n        ip_hash;\n    }\n\n server {\n\n        listen       80;\n        server_name   www.cc.com;\n        #osvue为项目名 weblogic 请求地址proxy_pass\n\t    location /osvue {\n            proxy_pass http://www.cc.com;\n            proxy_redirect off;\n            proxy_set_header X-Real-IP $remote_addr;\n            #后端的Web服务器可以通过X-Forwarded-For获取用户真实IP\n            proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\n            #以下是一些反向代理的配置，可选。\n            proxy_set_header Host $host:$server_port;\n            client_max_body_size 10m; #允许客户端请求的最大单文件字节数\n            client_body_buffer_size 128k; #缓冲区代理缓冲用户端请求的最大字节数，\n            proxy_connect_timeout 90; #nginx跟后端服务器连接超时时间(代理连接超时)\n            proxy_send_timeout 90; #后端服务器数据回传时间(代理发送超时)\n            proxy_read_timeout 90; #连接成功后，后端服务器响应时间(代理接收超时)\n            proxy_buffer_size 4k; #设置代理服务器（nginx）保存用户头信息的缓冲区大小\n            proxy_buffers 4 32k; #proxy_buffers缓冲区，网页平均在32k以下的设置\n            proxy_busy_buffers_size 64k; #高负荷下缓冲大小（proxy_buffers*2）\n            proxy_temp_file_write_size 64k;\n\t    }\n\n\t    error_page   404  /404.html;\n        error_page   500 502 503 504  /50x.html;\n\n        location = /50x.html {\n            root   html;\n        }\n\n\t\tlocation = /favicon.ico {\n            root   html;\n        }\n\n        # 动静分离\n        location ~* \\.(css|js|html|png|jpg|gif){\n            root ui;\n            expires :7d;\n        }\n    }\n\n\n\n\n#http.server.localtion语法\n\n\n# 基本语法： location [=|~|~*|^~]/uri/{...} \n\n# = 严格匹配, 如果这个查询匹配，将停止搜索并立即处理此请求 \n\n# ~ 区分大小写匹配（可用正则表达式） \n\n# ~* 不区分大小写匹配（可用正则表达式） \n\n# !~ 区分大小写匹配 \n\n# !~* 不区分大小写匹配 \n\n# ^~ 如果把这个前缀用于一个常规字符串，那么告诉nginx如果路径匹配那么不测试正则表达式\n\nlocation = /{\n#只匹配/查询\n}\n\nlocation /{\n#匹配任何查询，因为所有请求都以/开头。但是正则表达式和长的块规则将被优先查询匹配\n}\n\nlocation ^~ /images/{\n#匹配任何以/images/开头的查询并停止搜索。任何正则表达式将不会被测试。\n}\n\nlocation ~*.(gif|jpg|jpeg)${\n#匹配任何以gif|jpg|jpeg结尾的请求\n}\n</code></pre></div>',4);e.render=function(n,e){return o};export{e as default};
